const allItems = $input.all();

// Guard: no submissions — return a helpful empty report
if (!allItems.length) {
  const d = new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
  return [{ json: { html: '<p>No submissions found for this form. Verify the Form ID and ensure the form has at least one response.</p>', subject: '📊 Competition Report — ' + d + ' — No submissions found' } }];
}

const safeNum = v => (v == null || isNaN(Number(v))) ? null : Number(v);

function formatDuration(s) {
  if (s == null) return '—';
  s = Math.round(Number(s));
  const d = Math.floor(s / 86400);
  const h = Math.floor((s % 86400) / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sc = s % 60;
  if (d > 0) return `${d}d ${h}h ${m}m`;
  if (h > 0) return `${h}h ${m}m ${sc}s`;
  if (m > 0) return `${m}m ${sc}s`;
  return `${sc}s`;
}

function esc(str) {
  return String(str ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function fmtDate(dt) {
  if (!dt) return '—';
  const d = new Date(dt);
  if (isNaN(d.getTime())) return '—';
  return d.toLocaleString('en-GB', {
    day: '2-digit', month: 'short', year: 'numeric',
    hour: '2-digit', minute: '2-digit',
  });
}

function median(nums) {
  const a = nums.filter(n => n != null).map(n => Number(n)).sort((x, y) => x - y);
  if (!a.length) return null;
  const mid = Math.floor(a.length / 2);
  return a.length % 2 ? a[mid] : Math.round((a[mid - 1] + a[mid]) / 2);
}

function avg(nums) {
  const a = nums.filter(n => n != null).map(n => Number(n));
  if (!a.length) return null;
  return Math.round(a.reduce((s, v) => s + v, 0) / a.length);
}

// ─────────────────────────────────────────────────────────────────────────────
// Normalize submissions
// userOrgunit is already a resolved name from 🔗 Enrich with User Data
// ─────────────────────────────────────────────────────────────────────────────
const submissions = allItems.map(i => {
  const j = i.json || {};
  const seconds = safeNum(j.durationSeconds);
  return {
    submissionId: j.submissionId || j._id || null,
    userName: j.userName || 'Unknown',
    userEmail: j.userEmail || '',
    userOrgunit: j.userOrgunit || 'Unknown',
    submittedAt: j.submittedAt || null,
    seconds,
    durationFormatted: j.durationFormatted || formatDuration(seconds),
  };
});

const totalSubs = submissions.length;

// ─────────────────────────────────────────────────────────────────────────────
// Aggregate per participant
// ─────────────────────────────────────────────────────────────────────────────
const participantKey = s =>
  (s.userEmail ? s.userEmail.toLowerCase() : `${s.userName}::${s.userOrgunit}`).toLowerCase();

const pMap = new Map();
for (const s of submissions) {
  const key = participantKey(s);
  if (!pMap.has(key)) {
    pMap.set(key, {
      key,
      name: s.userName,
      email: s.userEmail,
      orgunit: s.userOrgunit,
      submissionsCount: 0,
      bestSeconds: null,
      bestSubmittedAt: null,
      _sum: 0,
      _count: 0,
    });
  }
  const p = pMap.get(key);
  p.submissionsCount++;
  if (s.seconds != null) {
    p._sum += s.seconds;
    p._count += 1;
    if (p.bestSeconds == null || s.seconds < p.bestSeconds) {
      p.bestSeconds = s.seconds;
      p.bestSubmittedAt = s.submittedAt;
    }
  }
  p.name = s.userName || p.name;
  p.orgunit = s.userOrgunit || p.orgunit;
  p.email = s.userEmail || p.email;
}

const participants = Array.from(pMap.values()).map(p => ({
  ...p,
  avgSeconds: p._count ? Math.round(p._sum / p._count) : null,
  bestFormatted: formatDuration(p.bestSeconds),
}));

participants.sort((a, b) => {
  if (a.bestSeconds == null && b.bestSeconds == null) return 0;
  if (a.bestSeconds == null) return 1;
  if (b.bestSeconds == null) return -1;
  return a.bestSeconds - b.bestSeconds;
});

const participantsCount = participants.length;
const fastest = participants[0] || null;
const slowest = participants[participants.length - 1] || null;
const bestTimes = participants.map(p => p.bestSeconds).filter(v => v != null);
const avgBestSeconds = avg(bestTimes);
const medianBestSeconds = median(bestTimes);

// ─────────────────────────────────────────────────────────────────────────────
// Org unit aggregation
// ─────────────────────────────────────────────────────────────────────────────
const ouMap = new Map();
for (const p of participants) {
  if (p.bestSeconds == null) continue;
  const ou = p.orgunit || 'Unknown';
  if (!ouMap.has(ou)) ouMap.set(ou, { name: ou, total: 0, count: 0 });
  const d = ouMap.get(ou);
  d.total += p.bestSeconds;
  d.count += 1;
}

const orgunits = Array.from(ouMap.values())
  .map(x => ({
    name: x.name,
    avgSeconds: x.count ? Math.round(x.total / x.count) : null,
    avgFormatted: formatDuration(x.count ? Math.round(x.total / x.count) : null),
    count: x.count,
  }))
  .sort((a, b) => (a.avgSeconds ?? 9e15) - (b.avgSeconds ?? 9e15))
  .slice(0, 15);

// ─────────────────────────────────────────────────────────────────────────────
// Bar chart helpers
// ─────────────────────────────────────────────────────────────────────────────
function barRow({ left, right, pct, color, muted, emphasis }) {
  const leftTxt = esc(left || '—');
  const rightTxt = esc(right || '—');
  const labelColor = muted ? '#6b7280' : '#111827';
  const rightColor = emphasis ? '#4f46e5' : '#6b7280';
  const weight = emphasis ? '800' : '600';
  const bgFallback = color.includes('linear-gradient') ? 'rgba(99,102,241,0.85)' : color;
  return `
    <tr>
      <td align="right" valign="middle" style="padding:6px 12px 6px 0;white-space:nowrap;color:${labelColor};font-size:13px;font-weight:${weight};width:180px">${leftTxt}</td>
      <td valign="middle" style="padding:6px 0;width:100%">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:separate">
          <tr>
            <td style="background:#eef2f7;border-radius:999px;height:12px;line-height:12px;font-size:0;overflow:hidden">
              <div style="display:block;background-color:${bgFallback};background:${color};height:12px;width:${pct}%;min-width:2px;border-radius:999px"></div>
            </td>
          </tr>
        </table>
      </td>
      <td align="right" valign="middle" style="padding:6px 0 6px 12px;white-space:nowrap;color:${rightColor};font-size:13px;font-weight:800;width:80px">${rightTxt}</td>
    </tr>
  `;
}

function buildParticipantsBarChart(rows) {
  const max = Math.max(...rows.map(r => r.bestSeconds || 0), 1);
  const body = rows.map((p, i) => barRow({
    left: p.name.length > 22 ? p.name.slice(0, 22) + '…' : p.name,
    right: p.bestFormatted,
    pct: Math.round(((p.bestSeconds || 0) / max) * 100),
    color: i < 3
      ? 'linear-gradient(90deg, rgba(99,102,241,0.95), rgba(139,92,246,0.95))'
      : 'rgba(99,102,241,0.75)',
    muted: false,
    emphasis: i < 3,
  })).join('');
  return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse">${body}</table>`;
}

function buildOrgunitBarChart(rows) {
  const max = Math.max(...rows.map(r => r.avgSeconds || 0), 1);
  const body = rows.map((ou, i) => barRow({
    left: ou.name.length > 22 ? ou.name.slice(0, 22) + '…' : ou.name,
    right: `${ou.avgFormatted} · ${ou.count}`,
    pct: Math.round(((ou.avgSeconds || 0) / max) * 100),
    color: i === 0
      ? 'linear-gradient(90deg, rgba(16,185,129,0.95), rgba(52,211,153,0.95))'
      : 'rgba(16,185,129,0.75)',
    muted: true,
    emphasis: i === 0,
  })).join('');
  return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse">${body}</table>`;
}

// ─────────────────────────────────────────────────────────────────────────────
// Leaderboard rows
// ─────────────────────────────────────────────────────────────────────────────
const medals = ['🥇', '🥈', '🥉'];
const top10 = participants.slice(0, 10);

const leaderboardRows = top10.map((p, idx) => {
  const bg = idx % 2 ? '#f9fafb' : '#ffffff';
  const medal = idx < 3 ? medals[idx] : String(idx + 1);
  return `
    <tr style="background:${bg}">
      <td align="center" valign="middle" style="padding:10px 12px;color:#6b7280;font-size:13px;font-weight:800;width:40px">${medal}</td>
      <td valign="middle" style="padding:10px 12px;color:#111827;font-size:14px;font-weight:700">${esc(p.name)}</td>
      <td valign="middle" style="padding:10px 12px;color:#6b7280;font-size:13px">${esc(p.orgunit)}</td>
      <td align="right" valign="middle" style="padding:10px 12px">
        <span style="display:inline-block;background:#eef2ff;color:#4f46e5;font-weight:800;border-radius:999px;padding:4px 10px;font-size:13px;white-space:nowrap">${esc(p.bestFormatted)}</span>
      </td>
      <td align="right" valign="middle" style="padding:10px 12px;color:#9ca3af;font-size:12px;white-space:nowrap">${fmtDate(p.bestSubmittedAt)}</td>
      <td align="right" valign="middle" style="padding:10px 12px;color:#9ca3af;font-size:12px;white-space:nowrap">${p.submissionsCount}</td>
    </tr>
  `;
}).join('');

// ─────────────────────────────────────────────────────────────────────────────
// HTML
// ─────────────────────────────────────────────────────────────────────────────
// Reference time label for the report header
const formData = $('🚀 Start here!').first().json;
const dateRaw = formData['Competition start date (optional)'] || '';
const timeRaw = formData['Competition start time (optional)'] || '';
const customStartRaw = dateRaw ? (dateRaw + (timeRaw ? 'T' + timeRaw : 'T00:00')) : '';
const customStartDt = customStartRaw ? new Date(customStartRaw) : null;
const refTimeLabel = (customStartDt && !isNaN(customStartDt.getTime()))
  ? 'from ' + customStartDt.toLocaleString('en-GB', { day: '2-digit', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' })
