const weekStr = new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
const fastestNamePlain = fastest?.name || '—';
const fastestTimePlain = fastest?.bestSeconds != null ? formatDuration(fastest.bestSeconds) : '—';
const safeFastestNameHtml = esc(fastestNamePlain);
const safeFastestTimeHtml = esc(fastestTimePlain);
