                  </td>
                </tr>
              </table>
            </td>
          </tr>

          <tr><td style="height:16px;line-height:16px;font-size:0;">&nbsp;</td></tr>

          <!-- KPI Cards -->
          <tr>
            <td>
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:separate">
                <tr>
                  <td valign="top" width="33.33%" style="padding:0 6px 0 0;">
                    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#ffffff;border-radius:14px;border-top:4px solid #f59e0b;box-shadow:0 2px 10px rgba(17,24,39,0.06);">
                      <tr>
