                          <div style="height:6px;line-height:6px;font-size:0;">&nbsp;</div>
                          <div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#f59e0b;font-size:26px;font-weight:900;line-height:1;">${safeFastestTimeHtml}</div>
                          <div style="margin-top:6px;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#9ca3af;font-size:11px;">Best time</div>
                          <div style="height:${kpiBottomSpacer}px;line-height:${kpiBottomSpacer}px;font-size:0;">&nbsp;</div>
