                      <tr>
                        <td style="padding:18px 16px;height:${kpiMinHeight}px;vertical-align:top;">
                          <div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#9ca3af;font-size:10px;letter-spacing:1.6px;text-transform:uppercase;font-weight:800;">Typical best time</div>
                          <div style="height:6px;line-height:6px;font-size:0;">&nbsp;</div>
                          <div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#111827;font-size:26px;font-weight:900;line-height:1;">${esc(formatDuration(avgBestSeconds))}</div>
                          <div style="margin-top:6px;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#9ca3af;font-size:11px;">Median: <span style="color:#6366f1;font-weight:900;">${esc(formatDuration(medianBestSeconds))}</span></div>
                          <div style="margin-top:2px;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#9ca3af;font-size:11px;">Slowest: <span style="color:#ef4444;font-weight:900;">${esc(formatDuration(slowest?.bestSeconds))}</span></div>
