          <tr>
            <td>
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#ffffff;border-radius:14px;overflow:hidden;box-shadow:0 2px 10px rgba(17,24,39,0.06);">
                <tr>
                  <td style="padding:20px 20px 10px;">
                    <div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#111827;font-size:16px;font-weight:900;">Top performers</div>
                    <div style="margin-top:4px;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#9ca3af;font-size:13px;">Ranked by each participant's best response time</div>
                  </td>
                </tr>
                <tr>
                  <td style="padding:6px 20px 14px;">${buildParticipantsBarChart(top10)}</td>
                </tr>
                <tr>
                  <td style="padding:0;">
                    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse">
                      <tr style="background:#f9fafb;border-top:1px solid #e5e7eb;border-bottom:1px solid #e5e7eb">
                        <td style="padding:10px 12px;color:#6b7280;font-size:11px;font-weight:900;text-transform:uppercase;letter-spacing:1px;" align="center">#</td>
                        <td style="padding:10px 12px;color:#6b7280;font-size:11px;font-weight:900;text-transform:uppercase;letter-spacing:1px;">Participant</td>
                        <td style="padding:10px 12px;color:#6b7280;font-size:11px;font-weight:900;text-transform:uppercase;letter-spacing:1px;">Org unit</td>
                        <td style="padding:10px 12px;color:#6b7280;font-size:11px;font-weight:900;text-transform:uppercase;letter-spacing:1px;" align="right">Best</td>
                        <td style="padding:10px 12px;color:#6b7280;font-size:11px;font-weight:900;text-transform:uppercase;letter-spacing:1px;" align="right">Submitted</td>
                        <td style="padding:10px 12px;color:#6b7280;font-size:11px;font-weight:900;text-transform:uppercase;letter-spacing:1px;" align="right">Subs</td>
                      </tr>
                      ${leaderboardRows}
                    </table>
                  </td>
                </tr>
              </table>
            </td>
          </tr>

          <tr><td style="height:18px;line-height:18px;font-size:0;">&nbsp;</td></tr>

          <!-- Org units -->
          ${orgunits.length ? `
          <tr>
            <td>
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#ffffff;border-radius:14px;overflow:hidden;box-shadow:0 2px 10px rgba(17,24,39,0.06);">
                <tr>
                  <td style="padding:20px 20px 10px;">
                    <div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#111827;font-size:16px;font-weight:900;">Org unit performance</div>
                    <div style="margin-top:4px;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#9ca3af;font-size:13px;">Average of participant best times per org unit</div>
                  </td>
                </tr>
                <tr>
                  <td style="padding:6px 20px 18px;">${buildOrgunitBarChart(orgunits)}</td>
                </tr>
              </table>
            </td>
          </tr>
          <tr><td style="height:18px;line-height:18px;font-size:0;">&nbsp;</td></tr>
          ` : ''}

          <!-- Footer -->
          <tr>
            <td align="center" style="padding:8px 6px 20px;">
              <div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#cbd5e1;font-size:11px;">
                Generated automatically by <span style="color:#94a3b8;font-weight:800;">n8n</span> · Powered by <span style="color:#94a3b8;font-weight:800;">Keephub</span>
              </div>
            </td>
          </tr>

        </table>
      </td>
    </tr>
  </table>
</body>
</html>`;

 const subject = `📊 Competition Report — ${weekStr} · 🏆 ${fastestNamePlain} in ${fastestTimePlain} · ${participantsCount} participant${participantsCount === 1 ? '' : 's'}`; 

 return [{ json: { html, subject } }];

// Guard: bail out early if no enrichment data available
const orgItems = $input.all();
if (!orgItems.length) return [];

const userItems = $('Get submitter details for a form submission').all();
const durationItems = $('Calculate response duration for a form submission').all();
const splitItems = $('✂️ Split into Items').all();

// Check if a custom competition start date/time was provided on the form
const formData = $('🚀 Start here!').first().json;
const dateRaw = formData['Competition start date (optional)'] || '';
const timeRaw = formData['Competition start time (optional)'] || '';
const customStartRaw = dateRaw ? (dateRaw + (timeRaw ? 'T' + timeRaw : 'T00:00')) : '';
const customStartDate = customStartRaw ? new Date(customStartRaw) : null;
const useCustomStart = customStartDate && !isNaN(customStartDate.getTime());

// Direct id -> name map from all orgchart nodes
const orgById = new Map();
for (const o of orgItems) {
  const n = o.json;
  if (!n?._id) continue;
  const id = String(n._id);
  if (!orgById.has(id)) {
    orgById.set(id, String(n.name || id).trim());
  }
}

function resolveOrgunit(orgunits) {
  if (!Array.isArray(orgunits) || orgunits.length === 0) return 'Unknown';
  // Try each orgunit the user belongs to — return the first one we have a name for
  // Prefer non-root nodes (more specific), so skip root#### if a better match exists
  const nonRoot = orgunits.find(id => !String(id).startsWith('root') && orgById.has(String(id)));
  if (nonRoot) return orgById.get(String(nonRoot));
  const any = orgunits.find(id => orgById.has(String(id)));
  if (any) return orgById.get(String(any));
  return String(orgunits[0]) || 'Unknown';
}

function parseDuration(str) {
  if (!str) return null;
  const d = parseInt(str.match(/(\d+)d/)?.[1] || 0);
  const h = parseInt(str.match(/(\d+)h/)?.[1] || 0);
  const m = parseInt(str.match(/(\d+)m/)?.[1] || 0);
  const s = parseInt(str.match(/(\d+)s/)?.[1] || 0);
  return d * 86400 + h * 3600 + m * 60 + s;
}

function formatDuration(totalSeconds) {
  if (totalSeconds == null) return '—';
  totalSeconds = Math.round(totalSeconds);
  const d = Math.floor(totalSeconds / 86400);
  const h = Math.floor((totalSeconds % 86400) / 3600);
  const m = Math.floor((totalSeconds % 3600) / 60);
  const s = totalSeconds % 60;
  if (d > 0) return `${d}d ${h}h ${m}m`;
  if (h > 0) return `${h}h ${m}m ${s}s`;
  if (m > 0) return `${m}m ${s}s`;
  return `${s}s`;
}

const count = Math.max(userItems.length, durationItems.length, splitItems.length);
const results = [];

for (let i = 0; i < count; i++) {
  const user = userItems[i]?.json || {};
  const dur = durationItems[i]?.json || {};
  const raw = splitItems[i]?.json || {};

  const submittedAt = dur.submittedAt || raw.createdAt || null;

  let durationSeconds = null;
  let durationStr = null;
  let durationFormatted = null;

  if (useCustomStart && submittedAt) {
    // Custom start provided — measure from that moment
    const subDate = new Date(submittedAt);
    if (!isNaN(subDate.getTime())) {
      durationSeconds = Math.max(0, Math.round((subDate.getTime() - customStartDate.getTime()) / 1000));
    }
  } else {
    // No custom start — fall back to Keephub API duration
    durationStr = dur.duration?.timeSinceFormCreated || null;
    durationSeconds = parseDuration(durationStr);
  }
  durationFormatted = formatDuration(durationSeconds);

  const fullName =
    user.name ||
    [user.firstName, user.insertion, user.lastName].filter(Boolean).join(' ').trim() ||
    user.loginName ||
    raw.createdBy ||
    'Unknown';

  const userOrgunit = resolveOrgunit(user.orgunits);

  results.push({
    json: {
      submissionId: raw._id || null,
      contentRef: raw.contentRef || null,
      submittedAt,
      durationSeconds,
      durationStr,
      durationFormatted,
      userName: fullName,
      userEmail: user.email || '',
      userPosition: user.position || '',
      userLevel: user.level || '',
      userOrgunit,
    }
  });
}

return results;

options.customCss:
@import url('https://fonts.googleapis.com/css2?family=Open+Sans:wght@400;600&display=swap');

* {
  font-family: 'Open Sans', sans-serif;
  box-sizing: border-box;
}

body {
  background: #f0eeff;
  margin: 0;
  padding: 0;
}

.container {
  min-height: 100vh;
  padding: 32px 16px;
  display: flex;
  justify-content: center;
  align-items: flex-start;
}

section {
  width: 100%;
  max-width: 448px;
}

.test-notice {
  background: #fefaf6;
  border: 1px solid #f6dcb7;
  border-radius: 8px;
  padding: 10px 16px;
  margin-bottom: 12px;
  text-align: center;
}

.test-notice p {
  color: #e6a23d;
  font-size: 12px;
  font-weight: 600;
  margin: 0;
}

hr {
  border: none;
  border-top: 1px solid #dbdfe7;
  margin: 12px 0;
}

.card {
  background: #ffffff;
  border-radius: 12px;
  box-shadow: 0px 4px 24px 0px rgba(99, 77, 255, 0.12);
  overflow: hidden;
  margin-bottom: 16px;
  border: none;
  padding: 0;
}

.form-header {
  background: linear-gradient(135deg, #634dff 0%, #7c3aed 100%);
  padding: 28px 24px;
  margin-bottom: 0;
  border-bottom: none;
}

.form-header h1 {
  font-size: 22px;
  font-weight: 600;
  color: #ffffff;
  margin: 0 0 8px 0;
  line-height: 1.3;
}

.form-header p {
  font-size: 13px;
  font-weight: 400;
  color: rgba(255, 255, 255, 0.8);
  margin: 0;
  line-height: 1.6;
}

.inputs-wrapper {
  padding: 24px 24px 8px 24px;
}

.form-group {
  margin-bottom: 18px;
}

.form-label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  color: #525356;
  margin-bottom: 6px;
}

.form-label.form-required::after {
  content: ' *';
  color: #ff6d5a;
}

.form-input {
  display: block;
  width: 100%;
  padding: 11px 14px;
  font-size: 14px;
  font-weight: 400;
  color: #525356;
  background: #fbfcfe;
  border: 1px solid #dbdfe7;
  border-radius: 8px;
  outline: none;
  transition: border-color 0.15s ease, box-shadow 0.15s ease;
}

.form-input:focus {
  border-color: #634dff;
  background: #ffffff;
  box-shadow: 0 0 0 3px rgba(99, 77, 255, 0.1);
}

.form-input::placeholder {
  color: #a0a3a8;
}

[class^="error-"] {
  font-size: 12px;
  color: #ea1f30;
  margin: 4px 0 0 0;
  display: none;
}

[class^="error-"].error-show {
  display: block;
}

#submit-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  width: calc(100% - 48px);
  margin: 0 24px 24px 24px;
  height: 48px;
  background: #ff6d5a;
  color: #ffffff;
  border: none;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: opacity 0.15s ease, transform 0.1s ease;
}

#submit-btn:hover {
  opacity: 0.9;
  transform: translateY(-1px);
}

#submit-btn:active {
  opacity: 1;
  transform: translateY(0);
}

#submit-btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
  transform: none;
}

#submit-btn span {
  display: none;
}

#submit-btn svg {
